 import java.util.zip.ZipEntry;
 import java.util.zip.ZipInputStream;

 public final class ZipUtils {

     private ZipUtils() {}

+    private static Path resolveZipEntry(Path destinationDir, String entryName) throws IOException {
+        Path destDir = destinationDir.toAbsolutePath().normalize();
+        Path destPath = destDir.resolve(entryName).normalize();
+        if (!destPath.startsWith(destDir)) {
+            throw new IOException("Blocked unzipping outside destination dir: " + entryName);
+        }
+        return destPath;
+    }
+
     public static void unzip(InputStream is, Path destinationDir) throws IOException {
         try (ZipInputStream zis = new ZipInputStream(new BufferedInputStream(is))) {
             ZipEntry entry;
             while ((entry = zis.getNextEntry()) != null) {
-                Path newPath = destinationDir.resolve(entry.getName());
+                Path newPath = resolveZipEntry(destinationDir, entry.getName());
                 if (entry.isDirectory()) {
                     Files.createDirectories(newPath);
                 } else {
                     Path parent = newPath.getParent();
                     if (parent != null) {
                         Files.createDirectories(parent);
                     }
                     Files.copy(zis, newPath, StandardCopyOption.REPLACE_EXISTING);
                 }
                 zis.closeEntry();
             }
         }
     }
 }

