+ * @param {Document} svgDoc Parsed SVG document.
+ */
+const sanitizeSvgDocument = svgDoc => {
+    if (!svgDoc || !svgDoc.documentElement) return;
+
+    // Only operate on SVG documents; otherwise clear the document element.
+    const root = svgDoc.documentElement;
+    if (String(root.nodeName).toLowerCase() !== 'svg') {
+        // If this isn't an SVG root, don't risk injecting arbitrary markup.
+        // Replace with an empty SVG.
+        const empty = svgDoc.createElementNS('http://www.w3.org/2000/svg', 'svg');
+        while (svgDoc.firstChild) svgDoc.removeChild(svgDoc.firstChild);
+        svgDoc.appendChild(empty);
+        return;
+    }
